export const getStyleProps = (props, name, classNamesState) => {
  const {
    cx,
    getStyles,
    getClassNames,
    className
  } = props;
  return {
    css: getStyles(name, props),
    className: cx(classNamesState !== null && classNamesState !== void 0 ? classNamesState : {}, getClassNames(name, props), className)
  };
};